export function resolveApiBaseUrl(explicitBaseUrl?: string) {
  if (explicitBaseUrl) {
    // If the explicit URL is relative (starts with /), use it directly on the client.
    // On the server, resolve it to a full URL using localhost.
    if (explicitBaseUrl.startsWith("/")) {
      if (typeof window !== "undefined") {
        return explicitBaseUrl;
      }
      // Server-side: resolve relative URL to localhost
      return `http://127.0.0.1:3000${explicitBaseUrl}`;
    }
    return explicitBaseUrl;
  }

  if (typeof window !== "undefined") {
    const { protocol, hostname } = window.location;
    return `${protocol}//${hostname}:8000/api/v1`;
  }

  return "http://127.0.0.1:8000/api/v1";
}
