import { useCallback, useEffect, useRef, useState } from "react";

interface PageLoaderProps {
  isLoading?: boolean;
  delay?: number;
  /** Maximum time (ms) the loader is allowed to block the viewport,
   *  regardless of isLoading. Prevents a permanent black screen if
   *  client-side JS / hydration stalls. Default: 4000 ms. */
  maxDuration?: number;
}

export function PageLoader({
  isLoading = true,
  delay = 300,
  maxDuration = 4000,
}: PageLoaderProps) {
  const [showLoader, setShowLoader] = useState(isLoading);
  const [isHidden, setIsHidden] = useState(false);
  const dismissedRef = useRef(false);

  // ── Dismiss sequence: fade out → remove from DOM ──────────
  const dismiss = useCallback(() => {
    if (dismissedRef.current) return;
    dismissedRef.current = true;

    setIsHidden(true);
    setTimeout(() => setShowLoader(false), 500);
  }, []);

  // ── React to isLoading changing to false ──────────────────
  useEffect(() => {
    if (!isLoading) {
      const timer = setTimeout(dismiss, delay);
      return () => clearTimeout(timer);
    }
  }, [isLoading, delay, dismiss]);

  // ── Safety net: auto-dismiss after maxDuration ────────────
  //    If hydration stalls or an error prevents `isLoading` from
  //    ever becoming false, the loader will still disappear so
  //    the user can see the page content.
  useEffect(() => {
    const maxTimer = setTimeout(dismiss, maxDuration);
    return () => clearTimeout(maxTimer);
  }, [maxDuration, dismiss]);

  if (!showLoader) return null;

  return (
    <div
      data-page-loader=""
      className={`fixed inset-0 z-[9999] flex items-center justify-center bg-[linear-gradient(135deg,var(--color-page)_0%,var(--color-page-strong)_100%)] transition-opacity duration-500 ease-[cubic-bezier(0.25,1,0.25,1)] ${
        isHidden
          ? "opacity-0 pointer-events-none"
          : "opacity-100 pointer-events-auto"
      }`}
      aria-hidden={isHidden}
    >
      <div className="flex flex-col items-center gap-6">
        <div className="relative w-12 h-12">
          <div className="absolute inset-0 rounded-full border-[3px] border-transparent border-t-accent border-r-accent-secondary animate-[page-loader-spin_1.2s_linear_infinite]"></div>
          <div className="absolute inset-[8px] rounded-full border-[3px] border-transparent border-t-accent-secondary animate-[page-loader-spin_1.8s_linear_infinite_reverse]"></div>
          <div className="absolute inset-[16px] rounded-full border-[3px] border-transparent border-t-accent animate-[page-loader-spin_2.4s_linear_infinite]"></div>
        </div>
        <p className="font-sans text-sm font-medium text-text-muted tracking-[0.08em] uppercase animate-[page-loader-fade_1.6s_ease-in-out_infinite]">
          Loading
        </p>
      </div>
    </div>
  );
}
