import type { FocusEvent } from "react";
import { ChevronDown } from "lucide-react";
import { MenuColumns } from "@/exxonim/components/navigation/MenuColumns";
import type { MenuColumn, MenuKey, MenuItem } from "@/exxonim/components/navigation/types";
import { routes } from "@/exxonim/routes";
import { cn } from "@/exxonim/utils/cn";

/**
 * Desktop navigation — rendered as a centered pill inside the header.
 *
 * LAYOUT ORDER (explicit, not API-driven):
 *   [Home] [About] [Services ▼] [Resources ▼] [Career] [Contact] [● Track Consultation]
 *
 * The "Track Consultation" link is rendered with a distinctive accent-colored
 * pill and animated indicator dot to highlight it as Exxonim's primary
 * differentiator service.
 *
 * BACKEND / ADMIN INTEGRATION NOTES:
 * ──────────────────────────────────
 * Nav structure is defined in staticNavigation.ts. To change the items,
 * order, or labels, edit that file — NOT this component.
 *
 * If API-driven navigation is re-enabled in the future, replace the
 * leftLinks/rightLinks/highlightLink props with a single navigationItems
 * prop and parse using utils/navigation.ts utilities.
 */
interface DesktopNavigationProps {
  brandName: string;
  leftLinks: MenuItem[];
  rightLinks: MenuItem[];
  highlightLink: MenuItem;
  desktopMenu: MenuKey | null;
  resourcesActive: boolean;
  resourcesColumns: MenuColumn[];
  resourcesMenuId: string;
  servicesActive: boolean;
  servicesColumns: MenuColumn[];
  servicesMenuId: string;
  closeAllMenus: () => void;
  isActive: (href: string) => boolean;
  onDropdownBlur: (event: FocusEvent<HTMLDivElement>) => void;
  setDesktopMenu: (menu: MenuKey | null) => void;
}

const navLinkBase =
  "relative inline-flex items-center justify-center h-10 px-4 text-sm font-medium text-text rounded-full transition-all hover:bg-accent-soft";
const navLinkActive = "bg-accent-soft text-accent";

export function DesktopNavigation({
  brandName,
  leftLinks,
  rightLinks,
  highlightLink,
  desktopMenu,
  resourcesActive,
  resourcesColumns,
  resourcesMenuId,
  servicesActive,
  servicesColumns,
  servicesMenuId,
  closeAllMenus,
  isActive,
  onDropdownBlur,
  setDesktopMenu,
}: DesktopNavigationProps) {
  return (
    <div className="hidden xl:flex items-center">
      <nav
        className="inline-flex items-center gap-1 p-1.5 rounded-full bg-surface-soft border border-border-soft"
        aria-label="Primary navigation"
      >
        {/* Left links (Home, About) */}
        {leftLinks.map((link) => (
          <a
            key={link.href}
            href={link.href}
            aria-current={isActive(link.href) ? "page" : undefined}
            onClick={closeAllMenus}
            className={cn(navLinkBase, isActive(link.href) && navLinkActive)}
          >
            {link.label}
          </a>
        ))}

        {/* Services dropdown */}
        <div
          className="relative"
          onMouseEnter={() => setDesktopMenu("services")}
          onMouseLeave={() => setDesktopMenu(null)}
          onFocusCapture={() => setDesktopMenu("services")}
          onBlur={onDropdownBlur}
        >
          <a
            href={routes.services}
            aria-expanded={desktopMenu === "services"}
            aria-controls={servicesMenuId}
            aria-current={servicesActive ? "page" : undefined}
            onClick={closeAllMenus}
            className={cn(navLinkBase, servicesActive && navLinkActive, "group")}
          >
            Services
            <ChevronDown
              className={cn(
                "ml-1 w-4 h-4 transition-transform",
                desktopMenu === "services" && "rotate-180"
              )}
              aria-hidden="true"
            />
          </a>

          <div
            id={servicesMenuId}
            aria-hidden={desktopMenu !== "services"}
            className={cn(
              "absolute top-full left-1/2 -translate-x-1/2 pt-2 transition-all",
              desktopMenu === "services"
                ? "opacity-100 visible translate-y-0"
                : "opacity-0 invisible -translate-y-2 pointer-events-none"
            )}
          >
            <div className="p-4 rounded-2xl bg-surface border border-border-soft shadow-popover min-w-[360px]">
              <div className="flex gap-4">
                <MenuColumns columns={servicesColumns} onNavigate={closeAllMenus} />
              </div>
              <div className="flex items-center gap-3 mt-4 pt-4 border-t border-border-soft">
                <a
                  href={routes.services}
                  onClick={closeAllMenus}
                  className="inline-flex items-center justify-center h-10 px-5 rounded-full bg-accent text-accent-contrast text-sm font-extrabold hover:bg-accent-hover transition-all"
                >
                  See More Services
                </a>
                <a
                  href={routes.contact}
                  onClick={closeAllMenus}
                  className="text-sm font-medium text-accent hover:underline"
                >
                  Contact {brandName}
                </a>
              </div>
            </div>
          </div>
        </div>

        {/* Resources dropdown */}
        <div
          className="relative"
          onMouseEnter={() => setDesktopMenu("resources")}
          onMouseLeave={() => setDesktopMenu(null)}
          onFocusCapture={() => setDesktopMenu("resources")}
          onBlur={onDropdownBlur}
        >
          <a
            href={routes.resources}
            aria-expanded={desktopMenu === "resources"}
            aria-controls={resourcesMenuId}
            aria-current={resourcesActive ? "page" : undefined}
            onClick={closeAllMenus}
            className={cn(navLinkBase, resourcesActive && navLinkActive, "group")}
          >
            Resources
            <ChevronDown
              className={cn(
                "ml-1 w-4 h-4 transition-transform",
                desktopMenu === "resources" && "rotate-180"
              )}
              aria-hidden="true"
            />
          </a>

          <div
            id={resourcesMenuId}
            aria-hidden={desktopMenu !== "resources"}
            className={cn(
              "absolute top-full left-1/2 -translate-x-1/2 pt-2 transition-all",
              desktopMenu === "resources"
                ? "opacity-100 visible translate-y-0"
                : "opacity-0 invisible -translate-y-2 pointer-events-none"
            )}
          >
            <div className="p-4 rounded-2xl bg-surface border border-border-soft shadow-popover min-w-[280px]">
              <div className="flex gap-4">
                <MenuColumns columns={resourcesColumns} onNavigate={closeAllMenus} />
              </div>
              <div className="flex items-center gap-3 mt-4 pt-4 border-t border-border-soft">
                <a
                  href={routes.resources}
                  onClick={closeAllMenus}
                  className="inline-flex items-center justify-center h-10 px-5 rounded-full bg-accent text-accent-contrast text-sm font-extrabold hover:bg-accent-hover transition-all"
                >
                  See More
                </a>
                <a
                  href={routes.contact}
                  onClick={closeAllMenus}
                  className="text-sm font-medium text-accent hover:underline"
                >
                  Ask a Question
                </a>
              </div>
            </div>
          </div>
        </div>

        {/* Right links (Career, Contact) */}
        {rightLinks.map((link) => (
          <a
            key={link.href}
            href={link.href}
            aria-current={isActive(link.href) ? "page" : undefined}
            onClick={closeAllMenus}
            className={cn(navLinkBase, isActive(link.href) && navLinkActive)}
          >
            {link.label}
          </a>
        ))}

        {/* Highlight link — Track Consultation (differentiator)
            Rendered as a distinctive accent pill with animated indicator dot.
            BACKEND: The label and href come from staticNavigation.ts highlightLink.
            The visual treatment (accent bg + pulsing dot) is hardcoded here. */}
        <a
          href={highlightLink.href}
          onClick={closeAllMenus}
          aria-current={isActive(highlightLink.href) ? "page" : undefined}
          className={cn(
            "relative inline-flex items-center gap-2 h-10 px-4 rounded-full text-sm font-extrabold transition-all",
            isActive(highlightLink.href)
              ? "bg-accent-hover text-accent-contrast ring-2 ring-accent/30"
              : "bg-accent text-accent-contrast hover:bg-accent-hover"
          )}
        >
          <span className="relative flex h-2 w-2" aria-hidden="true">
            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-accent-contrast opacity-75" />
            <span className="relative inline-flex rounded-full h-2 w-2 bg-accent-contrast" />
          </span>
          {highlightLink.label}
        </a>
      </nav>
    </div>
  );
}
